function MysteryChest({ onComplete, onClose }) {
  const [opened, setOpened] = useState(false);
  const [item] = useState(() => {
    const weights = { common:35, rare:35, epic:20, legendary:10 };
    let r=Math.random()*100, acc=0, rarity="common";
    for (const [k,v] of Object.entries(weights)){acc+=v;if(r<=acc){rarity=k;break;}}
    const pool = CHEST_ITEMS.filter(i=>i.rarity===rarity);
    return pool[Math.floor(Math.random()*pool.length)] || CHEST_ITEMS[0];
  });

  const rarityBg = { common:"#3b82f6", rare:"#a855f7", epic:"#ec4899", legendary:"#f59e0b" };
  const rarityGlow = { common:"rgba(59,130,246,0.3)", rare:"rgba(168,85,247,0.4)", epic:"rgba(236,72,153,0.4)", legendary:"rgba(245,158,11,0.5)" };

  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.9)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,backdropFilter:"blur(12px)"}}>
    <div style={{textAlign:"center",maxWidth:380}}>
      {!opened ? (
        <div>
          <div style={{fontSize:100,marginBottom:16,animation:"bounce 1s infinite",cursor:"pointer"}} onClick={()=>setOpened(true)}>📦</div>
          <h2 style={{color:"#fbbf24",fontSize:22,fontWeight:800,margin:"0 0 8px"}}>COFRE MISTERIOSO</h2>
          <p style={{color:"#94a3b8",fontSize:14,margin:"0 0 20px"}}>Toca el cofre para abrirlo</p>
          <button onClick={()=>setOpened(true)} style={{padding:"14px 48px",background:"linear-gradient(135deg,#f59e0b,#f97316)",border:"none",borderRadius:14,color:"white",fontSize:16,fontWeight:700,cursor:"pointer",animation:"glow 1.5s infinite"}}>ABRIR COFRE</button>
        </div>
      ) : (
        <div style={{animation:"chestOpen 0.8s ease"}}>
          <Confetti active={item.rarity==="legendary"||item.rarity==="epic"} />
          <div style={{width:160,height:160,margin:"0 auto 16px",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:72,background:`radial-gradient(circle,${rarityBg[item.rarity]}33,transparent)`,boxShadow:`0 0 60px ${rarityGlow[item.rarity]}`,border:`3px solid ${rarityBg[item.rarity]}`}}>
            {item.icon}
          </div>
          <div style={{fontSize:11,color:rarityBg[item.rarity],textTransform:"uppercase",letterSpacing:2,fontWeight:700,marginBottom:4}}>{item.rarity}</div>
          <div style={{fontSize:22,fontWeight:800,color:"#f1f5f9",marginBottom:4}}>{item.name}</div>
          <div style={{fontSize:14,color:"#94a3b8",marginBottom:20}}>{item.desc}</div>
          <button onClick={()=>{onComplete(item);onClose();}} style={{padding:"12px 40px",background:`linear-gradient(135deg,${rarityBg[item.rarity]},${rarityBg[item.rarity]}cc)`,border:"none",borderRadius:12,color:"white",fontSize:15,fontWeight:600,cursor:"pointer"}}>Recoger</button>
        </div>
      )}
    </div>
  </div>;
}

// ===================== BOSS BATTLE =====================
function BossBattle({ question, onComplete, onClose }) {
  const [hp, setHp] = useState(100);
  const [bossHp, setBossHp] = useState(100);
  const [selected, setSelected] = useState(null);
  const [phase, setPhase] = useState("intro"); // intro, fight, result
  const [shaking, setShaking] = useState(false);
  const [turn, setTurn] = useState(0);

  const attack = () => {
    if (selected === null) return;
    const correct = selected === question.correct;
    setShaking(true);
    setTimeout(()=>setShaking(false), 500);
    if (correct) {
      const dmg = 35 + Math.floor(Math.random()*20);
      const newBossHp = Math.max(0, bossHp - dmg);
      setBossHp(newBossHp);
      if (newBossHp <= 0) {
        setTimeout(()=>{ setPhase("result"); onComplete(true); }, 600);
      } else {
        const bossDmg = 10 + Math.floor(Math.random()*10);
        setTimeout(()=>setHp(h=>Math.max(0,h-bossDmg)), 400);
      }
    } else {
      const bossDmg = 30 + Math.floor(Math.random()*20);
      const newHp = Math.max(0, hp - bossDmg);
      setHp(newHp);
      if (newHp <= 0) {
        setTimeout(()=>{ setPhase("result"); onComplete(false); }, 600);
      }
    }
    setSelected(null);
    setTurn(t=>t+1);
  };

  if (phase === "intro") return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.92)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
      <div style={{textAlign:"center",animation:"bossEntrance 0.8s ease"}}>
        <div style={{fontSize:120,marginBottom:16}}>🐉</div>
        <h2 style={{color:"#ef4444",fontSize:28,fontWeight:900,margin:"0 0 4px",textShadow:"0 0 20px rgba(239,68,68,0.5)"}}>BOSS BATTLE!</h2>
        <p style={{color:"#fbbf24",fontSize:16,margin:"0 0 8px"}}>Data Dragon te desafia</p>
        <p style={{color:"#94a3b8",fontSize:13,margin:"0 0 24px"}}>Responde correctamente para atacar. Errores = dano masivo!</p>
        <button onClick={()=>setPhase("fight")} style={{padding:"14px 48px",background:"linear-gradient(135deg,#ef4444,#dc2626)",border:"none",borderRadius:14,color:"white",fontSize:16,fontWeight:700,cursor:"pointer",animation:"pulse 1s infinite"}}>LUCHAR</button>
      </div>
    </div>
  );

  if (phase === "result") return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.92)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
      <Confetti active={bossHp<=0} />
      <div style={{textAlign:"center"}}>
        <div style={{fontSize:80,marginBottom:16}}>{bossHp<=0?"🏆":"💀"}</div>
        <h2 style={{color:bossHp<=0?"#fbbf24":"#ef4444",fontSize:28,fontWeight:900,margin:"0 0 8px"}}>{bossHp<=0?"VICTORIA!":"DERROTA"}</h2>
        <p style={{color:"#94a3b8",fontSize:14,margin:"0 0 20px"}}>{bossHp<=0?"+500 XP de recompensa!":"El dragon te ha vencido. Intenta de nuevo."}</p>
        <button onClick={onClose} style={{padding:"12px 40px",background:"linear-gradient(135deg,#3b82f6,#2563eb)",border:"none",borderRadius:12,color:"white",fontSize:15,fontWeight:600,cursor:"pointer"}}>Continuar</button>
      </div>
    </div>
  );

  return (
    <div style={{position:"fixed",inset:0,background:"linear-gradient(180deg,#1a0a0a,#0f172a)",display:"flex",flexDirection:"column",zIndex:1000,padding:20,overflow:"auto"}}>
      {/* Boss area */}
      <div style={{textAlign:"center",marginBottom:16}}>
        <div style={{fontSize:64,animation:shaking?"shake 0.5s":"bounce 2s infinite"}}>🐉</div>
        <div style={{maxWidth:300,margin:"8px auto"}}>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:3}}>
            <span style={{color:"#ef4444",fontWeight:700}}>Data Dragon</span><span style={{color:"#94a3b8"}}>{bossHp}/100 HP</span>
          </div>
          <div style={{height:10,background:"rgba(148,163,184,0.1)",borderRadius:5,overflow:"hidden"}}>
            <div style={{height:"100%",width:`${bossHp}%`,background:"linear-gradient(90deg,#ef4444,#f97316)",borderRadius:5,transition:"width 0.5s"}}/>
          </div>
        </div>
      </div>
      {/* Question */}
      <div style={{maxWidth:600,margin:"0 auto",width:"100%",flex:1}}>
        <div style={{background:"rgba(30,41,59,0.8)",borderRadius:14,padding:18,border:"1px solid rgba(239,68,68,0.2)",marginBottom:12}}>
          <p style={{margin:0,fontSize:14,lineHeight:1.6,color:"#f1f5f9"}}>{question.question}</p>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:12}}>
          {question.options.map((o,i)=>(
            <button key={i} onClick={()=>setSelected(i)} style={{
              padding:"12px 16px",borderRadius:10,fontSize:13,textAlign:"left",cursor:"pointer",fontFamily:"inherit",lineHeight:1.4,
              background:selected===i?"rgba(59,130,246,0.2)":"rgba(30,41,59,0.6)",
              border:selected===i?"2px solid #3b82f6":"1px solid rgba(148,163,184,0.1)",
              color:selected===i?"#60a5fa":"#cbd5e1"
            }}>{o}</button>
          ))}
        </div>
        <button onClick={attack} disabled={selected===null} style={{
          width:"100%",padding:"13px",background:selected!==null?"linear-gradient(135deg,#ef4444,#dc2626)":"#374151",
          border:"none",borderRadius:12,color:"white",fontSize:15,fontWeight:700,
          cursor:selected!==null?"pointer":"not-allowed",opacity:selected!==null?1:0.5
        }}>⚔️ ATACAR</button>
      </div>
      {/* Player HP */}
      <div style={{maxWidth:300,margin:"16px auto 0"}}>
        <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:3}}>
          <span style={{color:"#34d399",fontWeight:700}}>Tu HP</span><span style={{color:"#94a3b8"}}>{hp}/100</span>
        </div>
        <div style={{height:10,background:"rgba(148,163,184,0.1)",borderRadius:5,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${hp}%`,background:"linear-gradient(90deg,#10b981,#34d399)",borderRadius:5,transition:"width 0.5s"}}/>
        </div>
      </div>
    </div>
  );
}

// ===================== ACHIEVEMENT POPUP =====================
function AchievementPopup({ achievement, onClose }) {
  useEffect(()=>{const t=setTimeout(onClose,3500);return()=>clearTimeout(t);},[]);
  return <div style={{
    position:"fixed",top:20,left:"50%",transform:"translateX(-50%)",zIndex:1500,
    background:"linear-gradient(135deg,#1e293b,#334155)",border:"2px solid #fbbf24",
    borderRadius:16,padding:"14px 24px",display:"flex",alignItems:"center",gap:12,
    boxShadow:"0 8px 40px rgba(251,191,36,0.3)",animation:"slideDown 0.5s ease"
  }}>
    <span style={{fontSize:32}}>{achievement.icon}</span>
    <div>
      <div style={{fontSize:10,color:"#fbbf24",fontWeight:700,textTransform:"uppercase",letterSpacing:1}}>Logro desbloqueado</div>
      <div style={{fontSize:15,fontWeight:700,color:"#f1f5f9"}}>{achievement.name}</div>
      <div style={{fontSize:11,color:"#94a3b8"}}>{achievement.desc}</div>
    </div>
  </div>;
}

// ===================== MAIN APP =====================
function App() {
  // Keyboard shortcuts
  useEffect(() => {
    const handleKey = (e) => {
      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
      const key = e.key;
      if (key >= '1' && key <= '6') {
        // Will be handled by quiz mode via ref
        document.dispatchEvent(new CustomEvent('quiz-key', { detail: { key } }));
      }
      if (key === 'Enter') {
        document.dispatchEvent(new CustomEvent('quiz-enter'));
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, []);

  const [mode, setMode] = useState("menu");
  const [qIdx, setQIdx] = useState(0);
  const [selAns, setSelAns] = useState(null); // null, number, or Set for multi-answer
  const [showRes, setShowRes] = useState(false);
  const [showDisc, setShowDisc] = useState(false);
  const [history, setHistory] = useState([]);
  const [selTopics, setSelTopics] = useState(new Set(TOPICS));
  const [filtQs, setFiltQs] = useState(QUESTIONS);
  const [hiddenOpts, setHiddenOpts] = useState(new Set());
  const qRef = useRef(null);

  // Game state
  const [xp, setXp] = useState(0);
  const [streak, setStreak] = useState(0);
  const [maxStreak, setMaxStreak] = useState(0);
  const [mult, setMult] = useState(1);
  const [multDur, setMultDur] = useState(0);
  const [score, setScore] = useState(0);
  const [answered, setAnswered] = useState(0);
  const [totalCorr, setTotalCorr] = useState(0);
  const [hardCorr, setHardCorr] = useState(0);
  const [fastCorr, setFastCorr] = useState(0);
  const [topicsOk, setTopicsOk] = useState(new Set());
  const [jackpot, setJackpot] = useState(false);
  const [chestsOpened, setChestsOpened] = useState(0);
  const [scratchUsed, setScratchUsed] = useState(0);
  const [powerupsUsed, setPowerupsUsed] = useState(0);
  const [bossWins, setBossWins] = useState(0);
  const [timeStart, setTimeStart] = useState(null);
  const [bookmarks, setBookmarks] = useState(new Set());

  // Reward queues
  const [showWheel, setShowWheel] = useState(false);
  const [showScratch, setShowScratch] = useState(false);
  const [showChest, setShowChest] = useState(false);
  const [showBoss, setShowBoss] = useState(false);
  const [bossQ, setBossQ] = useState(null);
  const [wheelSpins, setWheelSpins] = useState(0);
  const [scratchCards, setScratchCards] = useState(0);
  const [chestKeys, setChestKeys] = useState(0);
  const [bossKeys, setBossKeys] = useState(0);
  const [rewardQueue, setRewardQueue] = useState([]);

  // Inventory
  const [shields, setShields] = useState(0);
  const [skips, setSkips] = useState(0);
  const [fiftyFifty, setFiftyFifty] = useState(0);
  const [hints, setHints] = useState(0);
  const [doubleXP, setDoubleXP] = useState(0);
  const [showHint, setShowHint] = useState(false);

  // UI
  const [achievements, setAchievements] = useState(new Set());
  const [showAch, setShowAch] = useState(null);
  const [xpPop, setXpPop] = useState(null);
  const [showConfetti, setShowConfetti] = useState(false);
  const [showInventory, setShowInventory] = useState(false);

  const curQ = filtQs[qIdx];
  const isMulti = curQ && Array.isArray(curQ.correct);
  const multiCount = isMulti ? curQ.correct.length : 1;
  const curRank = [...RANKS].reverse().find(r=>xp>=r.minXP)||RANKS[0];
  const nextRank = RANKS[RANKS.indexOf(curRank)+1];
  const rankProg = nextRank?((xp-curRank.minXP)/(nextRank.minXP-curRank.minXP))*100:100;
  const pct = answered>0?Math.round((score/answered)*100):0;

  const getStats = useCallback(()=>({
    correct:totalCorr,maxStreak,fastCorrect:fastCorr,hardCorrect:hardCorr,
    jackpot,topicsOk:topicsOk.size,chestsOpened,scratchUsed,powerupsUsed,bossWins
  }),[totalCorr,maxStreak,fastCorr,hardCorr,jackpot,topicsOk,chestsOpened,scratchUsed,powerupsUsed,bossWins]);

  const checkAch = useCallback((stats)=>{
    ACHIEVEMENTS.forEach(a=>{
      if(!achievements.has(a.id)&&a.cond(stats)){
        setAchievements(p=>new Set([...p,a.id]));
        setShowAch(a);
        setXp(x=>x+75);
      }
    });
  },[achievements]);

  const startQuiz = (topics, qm) => {
    let qs = QUESTIONS.filter(q=>topics.has(q.topic));
    if(qm==="random") qs=[...qs].sort(()=>Math.random()-0.5);
    setFiltQs(qs); setQIdx(0); setSelAns(null); setShowRes(false); setShowDisc(false);
    setScore(0); setAnswered(0); setStreak(0); setHistory([]);
    setTimeStart(Date.now()); setHiddenOpts(new Set()); setShowHint(false);
    setMode("quiz");
  };

  const submitAnswer = () => {
    if(selAns===null) return;
    if(isMulti && selAns instanceof Set && selAns.size < multiCount) return;
    const correct = isMulti
      ? (selAns instanceof Set && selAns.size===curQ.correct.length && curQ.correct.every(c=>selAns.has(c)))
      : selAns===curQ.correct;
    const elapsed = (Date.now()-timeStart)/1000;
    let earned = 0;
    const newStreak = correct ? streak+1 : 0;

    if(correct){
      setScore(s=>s+1);
      setTotalCorr(t=>t+1);
      const base = curQ.difficulty===3?45:curQ.difficulty===2?30:20;
      const streakB = Math.min(newStreak*8,80);
      const speedB = elapsed<8?40:elapsed<15?20:elapsed<25?8:0;
      if(elapsed<8) setFastCorr(f=>f+1);
      if(curQ.difficulty===3) setHardCorr(h=>h+1);
      setTopicsOk(p=>new Set([...p,curQ.topic]));
      const effMult = doubleXP>0 ? mult*2 : mult;
      if(doubleXP>0) setDoubleXP(d=>d-1);
      earned = Math.round((base+streakB+speedB)*effMult);
      setXp(x=>x+earned);
      setXpPop({amount:earned,key:Date.now()});
      setStreak(newStreak);
      if(newStreak>maxStreak) setMaxStreak(newStreak);
      if(multDur>0){
        const nd=multDur-1;
        setMultDur(nd);
        if(nd<=0) setMult(1);
      }
      // Intermittent rewards!
      const q = [];
      if(newStreak===3||newStreak===7||newStreak===12) q.push("wheel");
      if(newStreak===5||newStreak===10) q.push("chest");
      if(Math.random()<0.15) q.push("wheel"); // 15% random wheel
      if(Math.random()<0.08) q.push("scratch"); // 8% random scratch
      if(Math.random()<0.04) q.push("chest"); // 4% random chest
      if(newStreak===10||bossKeys>0&&Math.random()<0.2) q.push("boss");
      if(q.length>0) setRewardQueue(prev=>[...prev,...q]);
    } else {
      if(shields>0){ setShields(s=>s-1); setStreak(streak); /* keep streak */ }
      else setStreak(0);
      earned=8;
      setXp(x=>x+8);
    }

    setAnswered(a=>a+1);
    setHistory(h=>[...h,{question:curQ,selected:selAns,correct,xp:earned,time:elapsed}]);
    setShowRes(true);

    setTimeout(()=>{
      const s = {
        correct:correct?totalCorr+1:totalCorr,
        maxStreak:correct?Math.max(maxStreak,newStreak):maxStreak,
        fastCorrect:(correct&&elapsed<8)?fastCorr+1:fastCorr,
        hardCorrect:(correct&&curQ.difficulty===3)?hardCorr+1:hardCorr,
        jackpot,topicsOk:correct?new Set([...topicsOk,curQ.topic]).size:topicsOk.size,
        chestsOpened,scratchUsed,powerupsUsed,bossWins
      };
      checkAch(s);
    },600);
  };

  const nextQ = () => {
    if(rewardQueue.length>0){
      const next = rewardQueue[0];
      setRewardQueue(q=>q.slice(1));
      if(next==="wheel") setShowWheel(true);
      else if(next==="scratch") setShowScratch(true);
      else if(next==="chest") setShowChest(true);
      else if(next==="boss"){ setBossQ(QUESTIONS[Math.floor(Math.random()*QUESTIONS.length)]); setShowBoss(true); }
      return;
    }
    advanceQ();
  };

  const advanceQ = () => {
    if(qIdx<filtQs.length-1){
      setQIdx(i=>i+1); setSelAns(null); setShowRes(false); setShowDisc(false);
      setTimeStart(Date.now()); setHiddenOpts(new Set()); setShowHint(false);
      if(qRef.current) qRef.current.scrollTop=0;
    } else setMode("results");
  };

  // Quiz keyboard shortcuts (placed after submitAnswer/nextQ/advanceQ)
  useEffect(() => {
    if (mode !== "quiz" || !curQ) return;
    const onKey = (e) => {
      const idx = parseInt(e.detail.key) - 1;
      if (idx >= 0 && idx < (curQ.options?.length || 0) && !showRes && !hiddenOpts.has(idx)) {
        if (isMulti) {
          setSelAns(prev => {
            const s = new Set(prev instanceof Set ? prev : []);
            if (s.has(idx)) s.delete(idx); else s.add(idx);
            return new Set(s);
          });
        } else {
          setSelAns(idx);
        }
      }
    };
    const onEnter = () => {
      if (!showRes && selAns !== null) submitAnswer();
      else if (showRes) nextQ();
    };
    document.addEventListener('quiz-key', onKey);
    document.addEventListener('quiz-enter', onEnter);
    return () => { document.removeEventListener('quiz-key', onKey); document.removeEventListener('quiz-enter', onEnter); };
  }, [mode, curQ, showRes, selAns, isMulti, hiddenOpts]);

  const handleWheelComplete = (prize) => {
    if(prize.xp) setXp(x=>x+prize.xp);
    if(prize.jackpot) { setJackpot(true); setShowConfetti(true); setTimeout(()=>setShowConfetti(false),3000); }
    if(prize.mult) { setMult(prize.mult); setMultDur(3); }
    if(prize.scratch) setScratchCards(s=>s+1);
    if(prize.chest) setChestKeys(k=>k+1);
    if(prize.power) { const r=Math.random(); if(r<0.3)setShields(s=>s+1); else if(r<0.6)setFiftyFifty(f=>f+1); else if(r<0.8)setHints(h=>h+1); else setDoubleXP(d=>d+1); setPowerupsUsed(p=>p+1); }
  };

  const handleScratchComplete = (prize) => {
    setScratchUsed(s=>s+1);
    if(prize.xp) setXp(x=>x+prize.xp);
    if(prize.mult) { setMult(prize.mult); setMultDur(3); }
    if(prize.freeze) setShields(s=>s+1);
    if(prize.skip) setSkips(s=>s+1);
  };

  const handleChestComplete = (item) => {
    setChestsOpened(c=>c+1);
    if(item.xp) setXp(x=>x+item.xp);
    if(item.freeze) setShields(s=>s+1);
    if(item.multDuration) { setMult(2); setMultDur(item.multDuration); }
    if(item.spin) setWheelSpins(w=>w+1);
    if(item.bossKey) setBossKeys(k=>k+1);
  };

  const handleBossComplete = (won) => {
    if(won){ setBossWins(b=>b+1); setXp(x=>x+500); setShowConfetti(true); setTimeout(()=>setShowConfetti(false),3000); }
  };

  const use5050 = () => {
    if(fiftyFifty<=0||showRes) return;
    setFiftyFifty(f=>f-1); setPowerupsUsed(p=>p+1);
    const wrong = curQ.options.map((_,i)=>i).filter(i=>i!==curQ.correct);
    const toHide = wrong.sort(()=>Math.random()-0.5).slice(0,2);
    setHiddenOpts(new Set(toHide));
  };

  const useHint = () => {
    if(hints<=0||showRes) return;
    setHints(h=>h-1); setPowerupsUsed(p=>p+1);
    setShowHint(true);
  };

  const useSkip = () => {
    if(skips<=0) return;
    setSkips(s=>s-1);
    advanceQ();
  };

  const useDoubleXPItem = () => {
    if(doubleXP>0) return; // already active
    setDoubleXP(1);
  };

  const totalPowerups = shields+fiftyFifty+hints+skips+doubleXP+scratchCards+chestKeys+bossKeys+wheelSpins;

  // ============ MENU ============
  if(mode==="menu"){
    return <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#0f172a,#1e293b,#0f172a)",color:"#e2e8f0",fontFamily:"'Inter',-apple-system,sans-serif"}}>
      <style>{CSS}</style>
      <div style={{maxWidth:800,margin:"0 auto",padding:"36px 20px"}}>
        <div style={{textAlign:"center",marginBottom:32}}>
          <div style={{display:"inline-flex",gap:10,background:"linear-gradient(135deg,#4285f4,#34a853)",padding:"7px 18px",borderRadius:50,marginBottom:14,fontSize:13,fontWeight:600,letterSpacing:1,textTransform:"uppercase"}}>Google Cloud</div>
          <h1 style={{fontSize:36,fontWeight:800,margin:"0 0 6px",background:"linear-gradient(135deg,#60a5fa,#a78bfa,#f472b6)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>Professional Data Engineer</h1>
          <p style={{fontSize:15,color:"#94a3b8",margin:0}}>Simulador gamificado con refuerzo intermitente</p>
        </div>

        {xp>0&&<div style={{background:"rgba(30,41,59,0.8)",borderRadius:16,padding:18,border:"1px solid rgba(148,163,184,0.1)",marginBottom:20,display:"flex",alignItems:"center",gap:14}}>
          <div style={{fontSize:36}}>{curRank.icon}</div>
          <div style={{flex:1}}>
            <div style={{display:"flex",justifyContent:"space-between"}}><span style={{fontSize:15,fontWeight:700,color:curRank.color}}>{curRank.name}</span><span style={{fontSize:14,color:"#fbbf24",fontWeight:700}}>{xp} XP</span></div>
            {nextRank&&<><div style={{height:5,background:"rgba(148,163,184,0.1)",borderRadius:3,marginTop:6,overflow:"hidden"}}><div style={{height:"100%",width:`${rankProg}%`,background:`linear-gradient(90deg,${curRank.color},${nextRank.color})`,borderRadius:3}}/></div>
            <div style={{fontSize:10,color:"#64748b",marginTop:3}}>{nextRank.minXP-xp} XP para {nextRank.icon} {nextRank.name}</div></>}
          </div>
        </div>}

        {achievements.size>0&&<div style={{background:"rgba(30,41,59,0.6)",borderRadius:12,padding:14,marginBottom:20,border:"1px solid rgba(148,163,184,0.08)"}}>
          <div style={{fontSize:12,fontWeight:600,color:"#94a3b8",marginBottom:8}}>Logros ({achievements.size}/{ACHIEVEMENTS.length})</div>
          <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
            {ACHIEVEMENTS.map(a=><div key={a.id} title={`${a.name}: ${a.desc}`} style={{width:34,height:34,borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,background:achievements.has(a.id)?"rgba(251,191,36,0.12)":"rgba(148,163,184,0.05)",border:achievements.has(a.id)?"1px solid rgba(251,191,36,0.3)":"1px solid rgba(148,163,184,0.08)",opacity:achievements.has(a.id)?1:0.25}}>{achievements.has(a.id)?a.icon:"🔒"}</div>)}
          </div>
        </div>}

        {totalPowerups>0&&<div style={{background:"rgba(30,41,59,0.6)",borderRadius:12,padding:14,marginBottom:20,border:"1px solid rgba(148,163,184,0.08)"}}>
          <div style={{fontSize:12,fontWeight:600,color:"#94a3b8",marginBottom:8}}>Inventario</div>
          <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
            {shields>0&&<span style={{background:"rgba(16,185,129,0.15)",color:"#34d399",padding:"3px 10px",borderRadius:20,fontSize:11}}>🛡️ x{shields}</span>}
            {fiftyFifty>0&&<span style={{background:"rgba(59,130,246,0.15)",color:"#60a5fa",padding:"3px 10px",borderRadius:20,fontSize:11}}>✂️ x{fiftyFifty}</span>}
            {hints>0&&<span style={{background:"rgba(251,191,36,0.15)",color:"#fbbf24",padding:"3px 10px",borderRadius:20,fontSize:11}}>💡 x{hints}</span>}
            {skips>0&&<span style={{background:"rgba(168,85,247,0.15)",color:"#c084fc",padding:"3px 10px",borderRadius:20,fontSize:11}}>⏭️ x{skips}</span>}
            {doubleXP>0&&<span style={{background:"rgba(239,68,68,0.15)",color:"#f87171",padding:"3px 10px",borderRadius:20,fontSize:11}}>⚡ x{doubleXP}</span>}
            {scratchCards>0&&<span style={{background:"rgba(236,72,153,0.15)",color:"#f472b6",padding:"3px 10px",borderRadius:20,fontSize:11}}>🎫 x{scratchCards}</span>}
            {chestKeys>0&&<span style={{background:"rgba(168,85,247,0.15)",color:"#a855f7",padding:"3px 10px",borderRadius:20,fontSize:11}}>📦 x{chestKeys}</span>}
            {bossKeys>0&&<span style={{background:"rgba(239,68,68,0.15)",color:"#ef4444",padding:"3px 10px",borderRadius:20,fontSize:11}}>🗝️ x{bossKeys}</span>}
            {wheelSpins>0&&<span style={{background:"rgba(245,158,11,0.15)",color:"#f59e0b",padding:"3px 10px",borderRadius:20,fontSize:11}}>🎰 x{wheelSpins}</span>}
          </div>
        </div>}

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:20}}>
          <button onClick={()=>startQuiz(new Set(TOPICS),"sequential")} style={{padding:"18px 12px",background:"linear-gradient(135deg,#1e40af,#3b82f6)",border:"none",borderRadius:16,color:"white",fontSize:14,fontWeight:700,cursor:"pointer",boxShadow:"0 4px 20px rgba(59,130,246,0.3)"}}>
            <div style={{fontSize:24,marginBottom:4}}>📝</div>Todas<div style={{fontSize:10,fontWeight:400,marginTop:3,opacity:0.8}}>{QUESTIONS.length} preguntas</div>
          </button>
          <button onClick={()=>startQuiz(new Set(TOPICS),"random")} style={{padding:"18px 12px",background:"linear-gradient(135deg,#7c3aed,#a855f7)",border:"none",borderRadius:16,color:"white",fontSize:14,fontWeight:700,cursor:"pointer",boxShadow:"0 4px 20px rgba(168,85,247,0.3)"}}>
            <div style={{fontSize:24,marginBottom:4}}>🔀</div>Aleatorio<div style={{fontSize:10,fontWeight:400,marginTop:3,opacity:0.8}}>Orden mezclado</div>
          </button>
          <button onClick={()=>{const qs=[...QUESTIONS].sort(()=>Math.random()-0.5).slice(0,50);setFiltQs(qs);setQIdx(0);setSelAns(null);setShowRes(false);setShowDisc(false);setScore(0);setAnswered(0);setStreak(0);setHistory([]);setTimeStart(Date.now());setHiddenOpts(new Set());setShowHint(false);setMode("quiz");}} style={{padding:"18px 12px",background:"linear-gradient(135deg,#b45309,#f59e0b)",border:"none",borderRadius:16,color:"white",fontSize:14,fontWeight:700,cursor:"pointer",boxShadow:"0 4px 20px rgba(245,158,11,0.3)"}}>
            <div style={{fontSize:24,marginBottom:4}}>🎯</div>Simulacro<div style={{fontSize:10,fontWeight:400,marginTop:3,opacity:0.8}}>50 al azar</div>
          </button>
        </div>

        <div style={{background:"rgba(30,41,59,0.8)",borderRadius:16,padding:20,border:"1px solid rgba(148,163,184,0.1)",marginBottom:18}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
            <div style={{fontSize:14,fontWeight:600,color:"#94a3b8"}}>Filtrar por tema</div>
            <div style={{display:"flex",gap:6}}>
              <button onClick={()=>setSelTopics(new Set(TOPICS))} style={{padding:"3px 10px",borderRadius:8,fontSize:10,fontWeight:600,cursor:"pointer",border:"1px solid rgba(52,211,153,0.3)",background:"rgba(52,211,153,0.08)",color:"#34d399"}}>Todos</button>
              <button onClick={()=>setSelTopics(new Set())} style={{padding:"3px 10px",borderRadius:8,fontSize:10,fontWeight:600,cursor:"pointer",border:"1px solid rgba(248,113,113,0.3)",background:"rgba(248,113,113,0.08)",color:"#f87171"}}>Ninguno</button>
            </div>
          </div>
          <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:8}}>
            {TOPICS.map(t=>{const cnt=QUESTIONS.filter(q=>q.topic===t).length;return <button key={t} onDoubleClick={()=>setSelTopics(new Set([t]))} onClick={()=>{const n=new Set(selTopics);n.has(t)?n.delete(t):n.add(t);setSelTopics(n)}} title="Doble click = solo este tema" style={{padding:"4px 10px",borderRadius:20,fontSize:11,fontWeight:500,cursor:"pointer",border:selTopics.has(t)?"2px solid #3b82f6":"2px solid rgba(148,163,184,0.15)",background:selTopics.has(t)?"rgba(59,130,246,0.12)":"transparent",color:selTopics.has(t)?"#60a5fa":"#64748b"}}>{t} <span style={{fontSize:9,opacity:0.7}}>({cnt})</span></button>})}
          </div>
          <div style={{fontSize:10,color:"#475569",marginBottom:8,fontStyle:"italic"}}>Doble click en un tema = solo ese tema</div>
          <button onClick={()=>{if(selTopics.size>0)startQuiz(selTopics,"sequential")}} style={{width:"100%",padding:"11px",background:selTopics.size>0?"linear-gradient(135deg,#059669,#10b981)":"#374151",border:"none",borderRadius:10,color:"white",fontSize:13,fontWeight:600,cursor:selTopics.size>0?"pointer":"not-allowed",opacity:selTopics.size>0?1:0.5}}>
            Iniciar con {QUESTIONS.filter(q=>selTopics.has(q.topic)).length} de {QUESTIONS.length} preguntas
          </button>
        </div>

        <div style={{background:"rgba(30,41,59,0.4)",borderRadius:12,padding:16,border:"1px solid rgba(148,163,184,0.06)",fontSize:12,color:"#64748b"}}>
          <div style={{fontWeight:600,color:"#94a3b8",marginBottom:6}}>Mecanicas de recompensa</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:4}}>
            <div>🎰 Ruleta por rachas + aleatorio</div><div>🎫 Rasca y gana sorpresa</div>
            <div>📦 Cofres con items de rareza</div><div>🐉 Batallas boss epicas</div>
            <div>🛡️ Escudos protege-racha</div><div>✂️ Power-ups 50/50 y pistas</div>
            <div>⚡ XP variable + multiplicadores</div><div>🏆 14 logros desbloqueables</div>
          </div>
        </div>
      </div>
    </div>;
  }

  // ============ RESULTS ============
  if(mode==="results"){
    const topicStats={};
    history.forEach(h=>{const t=h.question.topic;if(!topicStats[t])topicStats[t]={c:0,t:0};topicStats[t].t++;if(h.correct)topicStats[t].c++;});
    const totalXP=history.reduce((s,h)=>s+h.xp,0);
    return <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#0f172a,#1e293b,#0f172a)",color:"#e2e8f0",fontFamily:"'Inter',-apple-system,sans-serif"}}>
      <style>{CSS}</style>
      <Confetti active={pct>=80} />
      <div style={{maxWidth:700,margin:"0 auto",padding:"36px 20px"}}>
        <div style={{textAlign:"center",marginBottom:28}}>
          <div style={{fontSize:52,marginBottom:10}}>{pct>=80?"🎉":pct>=60?"📊":"📚"}</div>
          <h2 style={{fontSize:26,fontWeight:800,margin:"0 0 4px"}}>Resultado del Examen</h2>
          <p style={{color:"#94a3b8",fontSize:14,margin:0}}>{pct>=80?"Excelente!":pct>=60?"Buen progreso":"Sigue practicando"}</p>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:10,marginBottom:20}}>
          {[{l:"Puntos",v:`${pct}%`,c:pct>=70?"#34d399":"#f87171"},{l:"Correctas",v:`${score}/${answered}`,c:"#60a5fa"},{l:"XP",v:`+${totalXP}`,c:"#fbbf24"},{l:"Racha max",v:`x${maxStreak}`,c:"#a78bfa"}].map((s,i)=>
            <div key={i} style={{background:"rgba(30,41,59,0.8)",borderRadius:14,padding:16,textAlign:"center",border:"1px solid rgba(148,163,184,0.1)"}}>
              <div style={{fontSize:24,fontWeight:800,color:s.c}}>{s.v}</div><div style={{fontSize:10,color:"#94a3b8",marginTop:2}}>{s.l}</div>
            </div>
          )}
        </div>
        <div style={{background:"rgba(30,41,59,0.8)",borderRadius:14,padding:18,border:"1px solid rgba(148,163,184,0.1)",marginBottom:18}}>
          <div style={{fontSize:14,fontWeight:600,marginBottom:12}}>Por tema</div>
          {Object.entries(topicStats).sort((a,b)=>(a[1].c/a[1].t)-(b[1].c/b[1].t)).map(([topic,s])=>{
            const p=Math.round((s.c/s.t)*100);
            return <div key={topic} style={{marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",fontSize:11,marginBottom:2}}><span style={{color:"#cbd5e1"}}>{topic}</span><span style={{color:p>=70?"#34d399":"#f87171",fontWeight:600}}>{s.c}/{s.t}</span></div>
              <div style={{height:4,background:"rgba(148,163,184,0.1)",borderRadius:2,overflow:"hidden"}}><div style={{height:"100%",width:`${p}%`,background:p>=70?"#34d399":"#f87171",borderRadius:2}}/></div>
            </div>;
          })}
        </div>
        <div style={{background:"rgba(30,41,59,0.8)",borderRadius:14,padding:18,border:"1px solid rgba(148,163,184,0.1)",marginBottom:18,maxHeight:300,overflowY:"auto"}}>
          <div style={{fontSize:14,fontWeight:600,marginBottom:10}}>Revision</div>
          {history.map((h,i)=><div key={i} style={{display:"flex",gap:8,padding:"8px 0",borderBottom:i<history.length-1?"1px solid rgba(148,163,184,0.06)":"none"}}>
            <div style={{width:24,height:24,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:700,flexShrink:0,background:h.correct?"rgba(52,211,153,0.12)":"rgba(248,113,113,0.12)",color:h.correct?"#34d399":"#f87171"}}>{h.correct?"✓":"✗"}</div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:11,color:"#cbd5e1",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{h.question.question}</div>
              <div style={{fontSize:10,color:"#64748b",marginTop:2}}>{h.question.topic} • +{h.xp} XP{!h.correct&&<span style={{color:"#34d399",marginLeft:6}}>Resp: {Array.isArray(h.question.correct)?h.question.correct.map(c=>h.question.options[c].substring(0,2)).join(", "):h.question.options[h.question.correct].substring(0,2)}</span>}</div>
            </div>
          </div>)}
        </div>
        <div style={{display:"flex",gap:10}}>
          <button onClick={()=>setMode("menu")} style={{flex:1,padding:"12px",background:"linear-gradient(135deg,#3b82f6,#2563eb)",border:"none",borderRadius:12,color:"white",fontSize:14,fontWeight:600,cursor:"pointer"}}>Menu</button>
          <button onClick={()=>startQuiz(selTopics,"random")} style={{flex:1,padding:"12px",background:"linear-gradient(135deg,#7c3aed,#a855f7)",border:"none",borderRadius:12,color:"white",fontSize:14,fontWeight:600,cursor:"pointer"}}>Reintentar</button>
        </div>
      </div>
    </div>;
  }

  // ============ QUIZ ============
  return <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#0f172a,#1e293b,#0f172a)",color:"#e2e8f0",fontFamily:"'Inter',-apple-system,sans-serif"}}>
    <style>{CSS}</style>
    <Confetti active={showConfetti}/>
    {showWheel&&<SpinWheel onComplete={handleWheelComplete} onClose={()=>{setShowWheel(false);if(rewardQueue.length>0)setTimeout(nextQ,200);else advanceQ();}}/>}
    {showScratch&&<ScratchCard onComplete={handleScratchComplete} onClose={()=>{setShowScratch(false);if(rewardQueue.length>0)setTimeout(nextQ,200);else advanceQ();}}/>}
    {showChest&&<MysteryChest onComplete={handleChestComplete} onClose={()=>{setShowChest(false);if(rewardQueue.length>0)setTimeout(nextQ,200);else advanceQ();}}/>}
    {showBoss&&bossQ&&<BossBattle question={bossQ} onComplete={handleBossComplete} onClose={()=>{setShowBoss(false);setBossQ(null);if(rewardQueue.length>0)setTimeout(nextQ,200);else advanceQ();}}/>}
    {showAch&&<AchievementPopup achievement={showAch} onClose={()=>setShowAch(null)}/>}
    {xpPop&&<div key={xpPop.key} style={{position:"fixed",left:"50%",top:"35%",transform:"translate(-50%,-50%)",fontSize:30,fontWeight:900,color:"#fbbf24",zIndex:500,pointerEvents:"none",animation:"floatUp 1.3s ease-out forwards",textShadow:"0 2px 12px rgba(251,191,36,0.5)"}}>+{xpPop.amount} XP</div>}

    {/* Top bar */}
    <div style={{background:"rgba(15,23,42,0.95)",borderBottom:"1px solid rgba(148,163,184,0.08)",padding:"8px 16px",position:"sticky",top:0,zIndex:10,backdropFilter:"blur(10px)"}}>
      <div style={{maxWidth:800,margin:"0 auto"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:4}}>
          <button onClick={()=>setMode("menu")} style={{background:"rgba(148,163,184,0.08)",border:"none",borderRadius:6,color:"#94a3b8",padding:"4px 10px",fontSize:11,cursor:"pointer"}}>← Menu</button>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            {streak>=2&&<span style={{fontSize:12,fontWeight:700,color:streak>=5?"#f59e0b":streak>=3?"#f472b6":"#60a5fa",animation:"pulse 1s infinite"}}>🔥 x{streak}</span>}
            {mult>1&&<span style={{fontSize:11,fontWeight:700,color:"#34d399",animation:"pulse 0.8s infinite"}}>⚡x{mult}({multDur})</span>}
            <span style={{fontSize:11,color:"#64748b"}}><b style={{color:"#e2e8f0"}}>{qIdx+1}</b>/{filtQs.length} <span style={{color:"#475569"}}>({Math.round(((qIdx+1)/filtQs.length)*100)}%)</span></span>
            <span style={{fontSize:11,color:pct>=70?"#34d399":"#f87171",fontWeight:600}}>{score}/{answered}</span>
          </div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontSize:14}}>{curRank.icon}</span>
          <div style={{flex:1,height:3,background:"rgba(148,163,184,0.08)",borderRadius:2,overflow:"hidden"}}><div style={{height:"100%",width:`${((qIdx+1)/filtQs.length)*100}%`,background:"linear-gradient(90deg,#3b82f6,#a855f7)",borderRadius:2,transition:"width 0.3s"}}/></div>
          <span style={{fontSize:11,color:"#fbbf24",fontWeight:700}}>{xp} XP</span>
        </div>
      </div>
    </div>

    <div ref={qRef} style={{maxWidth:800,margin:"0 auto",padding:"16px 20px"}}>
      {/* Streak bar visual */}
      {streak>=2&&<div style={{display:"flex",alignItems:"center",gap:8,padding:"6px 14px",background:`rgba(${streak>=5?"245,158,11":streak>=3?"236,72,153":"59,130,246"},0.08)`,border:`1px solid rgba(${streak>=5?"245,158,11":streak>=3?"236,72,153":"59,130,246"},0.2)`,borderRadius:10,marginBottom:10}}>
        <div style={{display:"flex",gap:2}}>{Array.from({length:Math.min(streak,12)}).map((_,i)=><div key={i} style={{width:6,height:14+i*1.5,background:streak>=5?"#f59e0b":streak>=3?"#ec4899":"#3b82f6",borderRadius:2,opacity:0.5+i*0.04}}/>)}</div>
        <span style={{fontSize:13,fontWeight:800,color:streak>=5?"#f59e0b":streak>=3?"#ec4899":"#60a5fa"}}>RACHA x{streak}</span>
        {shields>0&&<span style={{fontSize:11,color:"#34d399",marginLeft:"auto"}}>🛡️ Protegida</span>}
      </div>}

      {/* Pending rewards indicator */}
      {(rewardQueue.length>0||scratchCards>0||chestKeys>0||wheelSpins>0)&&!showRes&&<div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:10}}>
        {rewardQueue.filter(r=>r==="wheel").length+wheelSpins>0&&<span style={{background:"rgba(245,158,11,0.1)",border:"1px solid rgba(245,158,11,0.25)",borderRadius:8,padding:"4px 10px",fontSize:11,color:"#fbbf24",animation:"glow 2s infinite"}}>🎰 {rewardQueue.filter(r=>r==="wheel").length+wheelSpins} giro{(rewardQueue.filter(r=>r==="wheel").length+wheelSpins)>1?"s":""}</span>}
        {scratchCards>0&&<span style={{background:"rgba(236,72,153,0.1)",border:"1px solid rgba(236,72,153,0.25)",borderRadius:8,padding:"4px 10px",fontSize:11,color:"#f472b6"}}>🎫 {scratchCards}</span>}
        {chestKeys>0&&<span style={{background:"rgba(168,85,247,0.1)",border:"1px solid rgba(168,85,247,0.25)",borderRadius:8,padding:"4px 10px",fontSize:11,color:"#c084fc"}}>📦 {chestKeys}</span>}
      </div>}

      {/* Topic + difficulty + powerups */}
      <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:12,flexWrap:"wrap"}}>
        <span style={{background:"rgba(59,130,246,0.12)",color:"#60a5fa",padding:"3px 9px",borderRadius:20,fontSize:10,fontWeight:600}}>{curQ.topic}</span>
        {isMulti&&<span style={{background:"rgba(245,158,11,0.12)",color:"#fbbf24",padding:"3px 9px",borderRadius:20,fontSize:10,fontWeight:600}}>Multi ({multiCount})</span>}
        <span style={{background:curQ.difficulty===3?"rgba(239,68,68,0.12)":"rgba(234,179,8,0.12)",color:curQ.difficulty===3?"#f87171":"#fbbf24",padding:"3px 9px",borderRadius:20,fontSize:10,fontWeight:600}}>{"★".repeat(curQ.difficulty)}</span>
        {mult>1&&<span style={{background:"rgba(16,185,129,0.12)",color:"#34d399",padding:"3px 9px",borderRadius:20,fontSize:10,fontWeight:700,animation:"pulse 1s infinite"}}>x{mult}</span>}
        <div style={{marginLeft:"auto",display:"flex",gap:4}}>
          {fiftyFifty>0&&!showRes&&<button onClick={use5050} title="50/50" style={{width:30,height:30,borderRadius:8,border:"1px solid rgba(59,130,246,0.3)",background:"rgba(59,130,246,0.1)",color:"#60a5fa",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✂️</button>}
          {hints>0&&!showRes&&<button onClick={useHint} title="Pista" style={{width:30,height:30,borderRadius:8,border:"1px solid rgba(251,191,36,0.3)",background:"rgba(251,191,36,0.1)",color:"#fbbf24",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>💡</button>}
          {skips>0&&!showRes&&<button onClick={useSkip} title="Skip" style={{width:30,height:30,borderRadius:8,border:"1px solid rgba(168,85,247,0.3)",background:"rgba(168,85,247,0.1)",color:"#c084fc",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>⏭️</button>}
          <button onClick={()=>{const s=new Set(bookmarks);s.has(curQ.id)?s.delete(curQ.id):s.add(curQ.id);setBookmarks(s)}} style={{background:"none",border:"none",color:bookmarks.has(curQ.id)?"#fbbf24":"#475569",fontSize:16,cursor:"pointer"}}>
            {bookmarks.has(curQ.id)?"★":"☆"}
          </button>
        </div>
      </div>

      {/* Hint box */}
      {showHint&&<div style={{background:"rgba(251,191,36,0.08)",border:"1px solid rgba(251,191,36,0.2)",borderRadius:10,padding:"10px 14px",marginBottom:10,fontSize:12,color:"#fbbf24"}}>
        💡 Pista: {curQ.explanation.split(".")[0]}.
      </div>}

      {/* Question */}
      <div style={{background:"rgba(30,41,59,0.8)",borderRadius:14,padding:22,border:"1px solid rgba(148,163,184,0.08)",marginBottom:14}}>
        <p style={{margin:0,fontSize:15,fontWeight:600,lineHeight:1.6,color:"#f1f5f9"}}>{curQ.question}</p>
      </div>

      {/* Options */}
      <div style={{display:"flex",flexDirection:"column",gap:7,marginBottom:14}}>
        {curQ.options.map((o,i)=>{
          if(hiddenOpts.has(i)) return <div key={i} style={{padding:"12px 16px",borderRadius:10,background:"rgba(148,163,184,0.03)",border:"1px dashed rgba(148,163,184,0.1)",color:"#334155",fontSize:13,fontStyle:"italic"}}>Eliminada</div>;
          const isSelected = selAns instanceof Set ? selAns.has(i) : selAns===i;
          const isCorrectOpt = Array.isArray(curQ.correct)?curQ.correct.includes(i):i===curQ.correct;
          let bg="rgba(30,41,59,0.6)",brd="1px solid rgba(148,163,184,0.08)",col="#cbd5e1",anim="";
          if(showRes){
            if(isCorrectOpt){bg="rgba(52,211,153,0.1)";brd="2px solid #34d399";col="#34d399";}
            else if(isSelected&&!isCorrectOpt){bg="rgba(248,113,113,0.1)";brd="2px solid #f87171";col="#f87171";anim="shake 0.4s";}
          } else if(isSelected){bg="rgba(59,130,246,0.12)";brd="2px solid #3b82f6";col="#60a5fa";}
          return <button key={i} onClick={()=>{if(!showRes){if(isMulti){setSelAns(prev=>{const s=new Set(prev instanceof Set?prev:[]);if(s.has(i))s.delete(i);else s.add(i);return new Set(s);})}else{setSelAns(i)}}}} style={{padding:"13px 16px",background:bg,border:brd,borderRadius:10,color:col,fontSize:13,textAlign:"left",cursor:showRes?"default":"pointer",lineHeight:1.4,fontFamily:"inherit",animation:anim,transition:"all 0.2s"}}><span style={{display:"flex",alignItems:"center",gap:8}}>{isMulti&&<span style={{width:18,height:18,borderRadius:4,border:isSelected?"2px solid #60a5fa":"2px solid rgba(148,163,184,0.3)",background:isSelected?"#3b82f6":"transparent",display:"inline-flex",alignItems:"center",justifyContent:"center",fontSize:10,color:"white",flexShrink:0}}>{isSelected?"✓":""}</span>}<span style={{flex:1}}>{o}</span><span style={{fontSize:9,color:"#475569",fontWeight:600,flexShrink:0,opacity:0.5}}>{i+1}</span></span></button>;
        })}
      </div>

      {/* Submit / Result */}
      {!showRes?(
        <button onClick={submitAnswer} disabled={selAns===null||(isMulti&&selAns instanceof Set&&selAns.size<multiCount)} style={{width:"100%",padding:"12px",background:(selAns!==null&&(!isMulti||selAns instanceof Set&&selAns.size>=multiCount))?"linear-gradient(135deg,#3b82f6,#2563eb)":"#374151",border:"none",borderRadius:12,color:"white",fontSize:14,fontWeight:600,cursor:(selAns!==null&&(!isMulti||selAns instanceof Set&&selAns.size>=multiCount))?"pointer":"not-allowed",opacity:(selAns!==null&&(!isMulti||selAns instanceof Set&&selAns.size>=multiCount))?1:0.5}}>{isMulti?`Comprobar (${selAns instanceof Set?selAns.size:0}/${multiCount} seleccionadas)`:"Comprobar"}</button>
      ):(
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          <div style={{background:selAns===curQ.correct?"rgba(52,211,153,0.06)":"rgba(248,113,113,0.06)",border:`1px solid ${selAns===curQ.correct?"rgba(52,211,153,0.15)":"rgba(248,113,113,0.15)"}`,borderRadius:12,padding:16}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
              <div style={{display:"flex",alignItems:"center",gap:6}}>
                <span style={{fontSize:16}}>{selAns===curQ.correct?"✅":"❌"}</span>
                <strong style={{color:selAns===curQ.correct?"#34d399":"#f87171",fontSize:13}}>{selAns===curQ.correct?"Correcto!":"Incorrecto"}</strong>
              </div>
              <span style={{fontSize:12,color:"#fbbf24",fontWeight:700}}>+{history[history.length-1]?.xp||0} XP</span>
            </div>
            <p style={{margin:0,fontSize:12,lineHeight:1.6,color:"#94a3b8"}}>{curQ.explanation}</p>
          </div>

          <button onClick={()=>setShowDisc(!showDisc)} style={{padding:"9px",background:"rgba(168,85,247,0.08)",border:"1px solid rgba(168,85,247,0.2)",borderRadius:10,color:"#c084fc",fontSize:12,fontWeight:600,cursor:"pointer"}}>
            💬 {showDisc?"Ocultar":"Ver"} discusion ({curQ.discussion.length})
          </button>

          {showDisc&&<div style={{background:"rgba(30,41,59,0.8)",borderRadius:10,padding:14,border:"1px solid rgba(148,163,184,0.06)"}}>
            {curQ.discussion.map((d,i)=><div key={i} style={{marginBottom:i<curQ.discussion.length-1?12:0,paddingBottom:i<curQ.discussion.length-1?12:0,borderBottom:i<curQ.discussion.length-1?"1px solid rgba(148,163,184,0.05)":"none"}}>
              <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:4}}>
                <div style={{width:24,height:24,borderRadius:"50%",background:`hsl(${i*120+200},60%,40%)`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700}}>{d.user[0]}</div>
                <span style={{fontSize:11,fontWeight:600,color:"#cbd5e1"}}>{d.user}</span>
              </div>
              <p style={{margin:"0 0 0 30px",fontSize:11,lineHeight:1.5,color:"#94a3b8"}}>{d.text}</p>
            </div>)}
          </div>}

          <button onClick={nextQ} style={{
            width:"100%",padding:"12px",border:"none",borderRadius:12,color:"white",fontSize:14,fontWeight:600,cursor:"pointer",
            background:rewardQueue.length>0?"linear-gradient(135deg,#f59e0b,#f97316)":"linear-gradient(135deg,#059669,#10b981)",
            animation:rewardQueue.length>0?"glow 1.5s infinite":"none"
          }}>
            {rewardQueue.length>0?`🎁 Reclamar recompensa (${rewardQueue.length})`:qIdx<filtQs.length-1?"Siguiente →":"Ver resultados"}
          </button>
        </div>
      )}
    </div>
  </div>;
}

export default App;
export {
  QUESTIONS,
  TOPICS,
  RANKS,
  ACHIEVEMENTS,
  CSS,
  Confetti,
  SpinWheel,
  ScratchCard,
  MysteryChest,
  BossBattle,
  AchievementPopup,
};
